# Storage interface and implementation

from book_types import Book, BookStatus

interface IStorage:
    def add_book(self, book: Book)
    def find_by_isbn(self, isbn: str) -> Book?
    def get_book_count(self) -> int

class LibraryStorage(IStorage):
    books: list[Book]
    total_added: int

    def __init__(self):
        self.books = []
        self.total_added = 0

    def add_book(self, book: Book):
        self.books.append(book)
        self.total_added = self.total_added + 1

    def find_by_isbn(self, isbn: str) -> Book?:
        for book in self.books:
            if book.isbn == isbn:
                return book
        return None

    def get_book_count(self) -> int:
        return self.total_added

    def get_available_count(self) -> int:
        count: int = 0
        for book in self.books:
            if book.status == BookStatus.AVAILABLE:
                count = count + 1
        return count

