# Library operations and management

from book_types import Book, BookStatus
from storage import IStorage, LibraryStorage

class LibraryOperations:
    storage: IStorage
    library_name: str

    def __init__(self, name: str, storage: IStorage):
        self.library_name = name
        self.storage = storage

    def register_book(self, title: str, author: str, isbn: str):
        book: Book = Book(title, author, isbn)
        self.storage.add_book(book)

    def checkout_book(self, isbn: str) -> bool:
        book_opt: Book? = self.storage.find_by_isbn(isbn)
        if book_opt is not None:
            if book_opt.status == BookStatus.AVAILABLE:
                book_opt.checkout()
                return True
        return False

    def return_book(self, isbn: str) -> bool:
        book_opt: Book? = self.storage.find_by_isbn(isbn)
        if book_opt is not None:
            if book_opt.status == BookStatus.CHECKED_OUT:
                book_opt.return_book()
                return True
        return False

    def get_status_summary(self) -> str:
        return self.library_name + " has " + str(self.storage.get_book_count()) + " books"
